import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { streamxApi } from '../services/api';

export default function Navbar() {
  const { user, logout, isAdmin } = useAuth();
  const adminUser = isAdmin();
  const [scrolled, setScrolled] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpen, setMenuOpen] = useState(false);
  const [notificationsOpen, setNotificationsOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [notificationsLoading, setNotificationsLoading] = useState(false);
  const searchRef = useRef(null);
  const notificationsRef = useRef(null);
  const notificationsButtonRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    if (searchOpen && searchRef.current) searchRef.current.focus();
  }, [searchOpen]);

  useEffect(() => {
    if (!user) return;

    const loadUnreadCount = async () => {
      try {
        const res = await streamxApi.getUnreadNotificationsCount();
        setUnreadCount(res.data?.count || 0);
      } catch {
        setUnreadCount(0);
      }
    };

    loadUnreadCount();
    const intervalId = window.setInterval(loadUnreadCount, 30000);
    return () => window.clearInterval(intervalId);
  }, [user]);

  useEffect(() => {
    if (!notificationsOpen) return;

    const loadNotifications = async () => {
      setNotificationsLoading(true);
      try {
        const res = await streamxApi.getNotifications();
        setNotifications(res.data || []);
      } catch {
        setNotifications([]);
      } finally {
        setNotificationsLoading(false);
      }
    };

    loadNotifications();
  }, [notificationsOpen]);

  useEffect(() => {
    const onClickOutside = (event) => {
      const clickedNotifications = notificationsRef.current?.contains(event.target);
      const clickedBell = notificationsButtonRef.current?.contains(event.target);
      if (!clickedNotifications && !clickedBell) {
        setNotificationsOpen(false);
      }
    };

    document.addEventListener('mousedown', onClickOutside);
    return () => document.removeEventListener('mousedown', onClickOutside);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/browse?search=${encodeURIComponent(searchQuery)}`);
      setSearchOpen(false);
      setSearchQuery('');
    }
  };

  const isActive = (path) => location.pathname === path;
  const displayName = user?.username || user?.name || 'Account';

  const handleNotificationClick = async (notification) => {
    try {
      if (!notification.read) {
        await streamxApi.markNotificationRead(notification._id);
        setNotifications((currentNotifications) => currentNotifications.map((item) => (
          item._id === notification._id ? { ...item, read: true } : item
        )));
        setUnreadCount((count) => Math.max(0, count - 1));
      }

      setNotificationsOpen(false);
      if (notification.link) {
        navigate(notification.link);
      }
    } catch {
      setNotificationsOpen(false);
      if (notification.link) {
        navigate(notification.link);
      }
    }
  };

  const handleMarkAllRead = async () => {
    try {
      await streamxApi.markAllNotificationsRead();
      setNotifications((currentNotifications) => currentNotifications.map((item) => ({ ...item, read: true })));
      setUnreadCount(0);
    } catch {
      // Keep the UI responsive even if the bulk update fails.
    }
  };

  return (
    <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
      {/* Logo */}
      <Link to="/home" className="navbar-logo">
        CINEVERSE
      </Link>

      {/* Nav Links */}
      <div className="navbar-links">
        {[
          { label: 'Home', path: '/home' },
          { label: 'Browse', path: '/browse' },
          { label: 'Watchlist', path: '/watchlist' },
          { label: 'Reels', path: '/reels' },
          { label: 'Discussions', path: '/discussions' },
          ...(!adminUser ? [{ label: 'Pricing', path: '/pricing' }] : []),
        ].map(({ label, path }) => (
          <Link key={path} to={path} className={`navbar-link ${isActive(path) ? 'active' : ''}`}>
            {label}
          </Link>
        ))}
      </div>

      {/* Right Side */}
      <div className="navbar-actions">
        {/* Search */}
        <div className="navbar-search-box">
          {searchOpen ? (
            <form onSubmit={handleSearch} style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <input
                ref={searchRef}
                type="text"
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                placeholder="Search titles..."
                className="navbar-search-input"
              />
              <button
                type="button"
                onClick={() => setSearchOpen(false)}
                className="navbar-button"
              >✕</button>
            </form>
          ) : (
            <button
              onClick={() => setSearchOpen(true)}
              className="navbar-button"
            >🔍</button>
          )}
        </div>

        {/* Notifications */}
        <div style={{ position: 'relative' }} ref={notificationsRef}>
          <button
            ref={notificationsButtonRef}
            onClick={() => setNotificationsOpen((open) => !open)}
            className={`navbar-button ${notificationsOpen ? 'active' : ''}`}
            title="Notifications"
          >
            🔔
            {unreadCount > 0 && (
              <span className="navbar-badge">{unreadCount}</span>
            )}
          </button>

          {notificationsOpen && (
            <div className="navbar-dropdown">
              <div className="navbar-dropdown-header">
                <div>
                  <div className="navbar-dropdown-title">Notifications</div>
                  <div className="navbar-dropdown-subtitle">{unreadCount} unread</div>
                </div>
                <button
                  type="button"
                  onClick={handleMarkAllRead}
                  style={{
                    background: 'transparent',
                    border: '1px solid var(--border)',
                    color: 'var(--text)',
                    borderRadius: '999px',
                    padding: '6px 10px',
                    fontSize: '0.78rem',
                    cursor: 'pointer'
                  }}
                >
                  Mark all read
                </button>
              </div>

              <div className="navbar-dropdown-content">
                {notificationsLoading ? (
                  <div style={{ padding: '16px', color: 'var(--text-dim)', fontSize: '0.88rem' }}>Loading notifications...</div>
                ) : notifications.length === 0 ? (
                  <div style={{ padding: '16px', color: 'var(--text-dim)', fontSize: '0.88rem' }}>No notifications yet.</div>
                ) : (
                  notifications.map((notification) => (
                    <button
                      key={notification._id}
                      type="button"
                      onClick={() => handleNotificationClick(notification)}
                      className={`navbar-dropdown-item ${!notification.read ? 'unread' : ''}`}
                    >
                      <div className="navbar-dropdown-item-title">
                        <strong>{notification.title}</strong>
                        {!notification.read && <span className="navbar-dropdown-item-new">New</span>}
                      </div>
                      <div className="navbar-dropdown-item-desc">{notification.message}</div>
                    </button>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        {/* User Menu */}
        <div style={{ position: 'relative' }}>
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className={`navbar-user-button ${menuOpen ? 'active' : ''}`}
          >
            <span style={{ fontSize: '1rem' }}>👤</span>
            <span>{displayName}</span>
            <span style={{ fontSize: '0.7rem', opacity: 0.6 }}>{menuOpen ? '▲' : '▼'}</span>
          </button>
          {menuOpen && (
            <div className="navbar-user-menu">
              <div className="navbar-user-info">
                <div className="navbar-user-label">Signed in as</div>
                <div className="navbar-user-email">{user?.email}</div>
              </div>
              {!adminUser ? (
                <>
                  <Link
                    to="/profile"
                    onClick={() => setMenuOpen(false)}
                    className="navbar-user-item"
                  >
                    👤 Profile
                  </Link>
                </>
              ) : (
                <Link
                  to="/admin"
                  onClick={() => setMenuOpen(false)}
                  className="navbar-user-item"
                >
                  ⚙️ Admin Dashboard
                </Link>
              )}
              <button
                onClick={() => { logout(); navigate('/'); }}
                className="navbar-user-signout"
              >🚪 Sign Out</button>
            </div>
          )}
        </div>
      </div>
    </nav>
